package main

import (
	"encoding/xml"
	"fmt"
	"io/ioutil"
	"os"
)

type Config struct {
	XMLName xml.Name `xml:"config"`
	Servers []Server   `xml:"server"`
}

type Server struct {
	Name  string `xml:"name,attr"`
	IP    string `xml:"ip,attr"`
	Port  int    `xml:"port,attr"`
	Admin string `xml:"admin,attr"`
}

func main() {
	xmlFile, err := os.Open("config.xml")
	if err != nil {
		fmt.Println(err)
		return
	}
	defer xmlFile.Close()

	byteValue, _ := ioutil.ReadAll(xmlFile)

	var config Config
	err = xml.Unmarshal(byteValue, &config)
	if err != nil {
		fmt.Println(err)
		return
	}

	for _, server := range config.Servers {
		fmt.Printf("Server: %s\nIP: %s\nPort: %d\nAdmin: %s\n\n", server.Name, server.IP, server.Port, server.Admin)
	}
}